SELECT
*
FROM t_asset
where
deleted_flag = #{queryForm.deletedFlag}


    AND status = #{queryForm.status}



    AND status in

        #{item}




    and DATE_FORMAT(create_time, '%Y-%m-%d') >= #{queryForm.startTime}


    and DATE_FORMAT(create_time, '%Y-%m-%d') <= #{queryForm.endTime}



    AND ( INSTR(asset_name,#{queryForm.keywords})
    OR INSTR(asset_no,#{queryForm.keywords})
    )


    AND category_id = #{queryForm.categoryId}


    AND location_id = #{queryForm.locationId}


    AND department_id = #{queryForm.departmentId}


    AND enterprise_id = #{queryForm.enterpriseId}


    ORDER BY create_time DESC

